import QtQuick
import QtQuick3D
import QtQuick.Controls
import QtQuick.Layouts

Window {
    visible: true
    width: 800
    height: 600
    title: qsTr(&quot;Quick3D Antialiasing Example&quot;)
    color: &quot;black&quot;

    View3D {
        id: view3D
        property real animationValue: 0.0
        anchors.fill: parent

        SequentialAnimation on animationValue {
            id: modelAnimation
            running: false
            NumberAnimation {
                from: 0.0
                to: 1.0
                duration: 1000
                easing.type: Easing.InOutQuad
            }
            NumberAnimation {
                from: 1.0
                to: 0.0
                duration: 1000
                easing.type: Easing.InOutQuad
            }
        }

        PerspectiveCamera {
            z: 500
        }

        DirectionalLight {
            eulerRotation.x: -30
        }
        environment: SceneEnvironment {
            id: sceneEnvironment
            clearColor: &quot;#f0f0f0&quot;
            backgroundMode: SceneEnvironment.Color

            antialiasingMode: modeButton1.checked ? SceneEnvironment.NoAA : modeButton2.checked
                                                    ? SceneEnvironment.SSAA : modeButton3.checked
                                                      ? SceneEnvironment.MSAA : SceneEnvironment.ProgressiveAA

            antialiasingQuality: qualityButton1.checked ? SceneEnvironment.Medium : qualityButton2.checked
                                                          ? SceneEnvironment.High : SceneEnvironment.VeryHigh
            temporalAAEnabled: temporalModeButton.checked
            temporalAAStrength: temporalStrengthSlider.value
        }

        Node {
            id: scene

            Model {
                source: &quot;#Cube&quot;
                eulerRotation.y: 45
                eulerRotation.x: 30 + view3D.animationValue * 100
                scale: Qt.vector3d(2, 2, 2)
                materials: DefaultMaterial {
                    diffuseColor: &quot;#4aee45&quot;
                }
            }

            Model {
                source: &quot;#Cube&quot;
                x: 200
                y: 150 + view3D.animationValue * 10
                eulerRotation.y: 5
                eulerRotation.x: 5
                scale: Qt.vector3d(0.5, 0.5, 0.5)
                materials: DefaultMaterial {
                    diffuseColor: &quot;#faee45&quot;
                }
            }

            Model {
                source: &quot;#Sphere&quot;
                x: 120
                y: -40
                z: 160 + view3D.animationValue * 40
                scale: Qt.vector3d(1.5, 1.5, 1.5)
                materials: DefaultMaterial {
                    diffuseColor: Qt.rgba(0.8, 0.8, 0.8, 1.0)
                }
            }
        }
    }

    Frame {
        background: Rectangle {
            color: &quot;#c0c0c0&quot;
            border.color: &quot;#202020&quot;
        }
        anchors.top: parent.top
        anchors.left: parent.left
        anchors.margins: 10
        ColumnLayout {
            id: settingsArea
            Text {
                Layout.alignment: Qt.AlignHCenter
                font.bold: true
                text: &quot;antialiasingMode&quot;
            }
            RadioButton {
                id: modeButton1
                checked: true
                text: qsTr(&quot;NoAA&quot;)
            }
            RadioButton {
                id: modeButton2
                text: qsTr(&quot;SSAA&quot;)
            }
            RadioButton {
                id: modeButton3
                text: qsTr(&quot;MSAA&quot;)
            }
            RadioButton {
                id: modeButton4
                text: qsTr(&quot;ProgressiveAA&quot;)
            }
            Rectangle {
                Layout.fillWidth: true
                height: 1
                color: &quot;#909090&quot;
            }
            Text {
                Layout.alignment: Qt.AlignHCenter
                font.bold: true
                text: &quot;antialiasingQuality&quot;
            }
            ButtonGroup {
                buttons: antialiasingQualityColumn.children
            }
            ColumnLayout {
                id: antialiasingQualityColumn
                RadioButton {
                    id: qualityButton1
                    text: qsTr(&quot;Medium&quot;)
                }
                RadioButton {
                    id: qualityButton2
                    checked: true
                    text: qsTr(&quot;High&quot;)
                }
                RadioButton {
                    id: qualityButton3
                    text: qsTr(&quot;VeryHigh&quot;)
                }
            }
            Rectangle {
                Layout.fillWidth: true
                height: 1
                color: &quot;#909090&quot;
            }
            CheckBox {
                id: temporalModeButton
                text: &quot;temporalAAEnabled&quot;
            }
            Item { width: 1; height: 10 }
            Slider {
                id: temporalStrengthSlider
                from: 0.0
                to: 2.0
                value: 0.3
                Text {
                    anchors.horizontalCenter: parent.horizontalCenter
                    anchors.bottom: parent.verticalCenter
                    anchors.bottomMargin: 16
                    text: &quot;temporalAAStrength: &quot; + temporalStrengthSlider.value.toFixed(2);
                    z: 10
                }
            }
            Rectangle {
                Layout.fillWidth: true
                height: 1
                color: &quot;#909090&quot;
            }
            Button {
                id: animationButton
                Layout.alignment: Qt.AlignHCenter
                text: &quot;Animate!&quot;
                onClicked: {
                    modelAnimation.restart();
                }
            }
        }
    }
}
